export interface OfflineApiProxyRequest {
    type: 'offline-request';
    request: {
        method: string;
        url: string;
        body: string | null;
    };
}

export interface OfflineApiProxyResponse {
    status: number;
    headers?: Record<string, string>;
    body?: unknown;
}

export interface ServiceWorkerLikeClient {
    visibilityState?: string;
    postMessage(message: unknown, transfer?: Transferable[]): void;
}

export type MatchClients = () => Promise<ServiceWorkerLikeClient[]>;

export interface NetworkFirstApiOptions {
    timeoutMs?: number;
}

function jsonResponse(status: number, payload: Record<string, unknown>): Response {
    return new Response(JSON.stringify(payload), {
        status,
        headers: { 'Content-Type': 'application/json' },
    });
}

async function requestBodyText(request: Request): Promise<string | null> {
    if (request.method === 'GET' || request.method === 'HEAD') {
        return null;
    }

    const body = await request.clone().text();
    return body.length > 0 ? body : null;
}

export async function proxyApiRequestToClient(
    request: Request,
    matchClients: MatchClients,
    timeoutMs = 5000,
): Promise<Response> {
    const allClients = await matchClients();
    const targetClient = allClients.find((client) => client.visibilityState === 'visible') ?? allClients[0];

    if (!targetClient) {
        return jsonResponse(503, { error: 'Offline request failed: no active client available' });
    }

    const channel = new MessageChannel();
    const payload: OfflineApiProxyRequest = {
        type: 'offline-request',
        request: {
            method: request.method,
            url: request.url,
            body: await requestBodyText(request),
        },
    };

    const responsePromise = new Promise<OfflineApiProxyResponse>((resolve, reject) => {
        const timer = setTimeout(() => {
            channel.port1.close();
            reject(new Error('Offline API proxy timed out'));
        }, timeoutMs);

        channel.port1.onmessage = (event: MessageEvent<OfflineApiProxyResponse>) => {
            clearTimeout(timer);
            channel.port1.close();
            resolve(event.data);
        };
    });

    targetClient.postMessage(payload, [channel.port2]);

    try {
        const proxied = await responsePromise;
        if (!proxied) {
            return jsonResponse(503, { error: 'Offline request failed: empty client response' });
        }

        const headers = new Headers(proxied.headers ?? {});
        const contentType = headers.get('Content-Type') ?? headers.get('content-type');

        if (proxied.status === 204) {
            return new Response(null, { status: 204, headers });
        }

        const body = typeof proxied.body === 'string'
            ? proxied.body
            : contentType?.includes('application/json')
                ? JSON.stringify(proxied.body ?? {})
                : String(proxied.body ?? '');

        return new Response(body, { status: proxied.status ?? 500, headers });
    } catch (error) {
        return jsonResponse(503, {
            error: 'Offline request failed: unable to route to local handler',
            detail: error instanceof Error ? error.message : 'unknown',
        });
    }
}

export async function networkFirstApi(
    request: Request,
    fetchImpl: typeof fetch,
    proxyFallback: (request: Request) => Promise<Response>,
    options: NetworkFirstApiOptions = {},
): Promise<Response> {
    const timeoutMs = options.timeoutMs ?? 15000;
    const abortController = new AbortController();
    const timer = setTimeout(() => abortController.abort(), timeoutMs);

    // Clone the request so that if the fetch fails, the proxyFallback can still read the body
    const requestClone = request.clone();

    try {
        // NOTE: For the Chrome flag "Insecure origins treated as secure" to bypass Mixed Content
        // for service worker fetches, the flag must include the FULL origin WITH port, e.g.:
        //   http://192.168.178.170:3000,http://192.168.178.18:3000
        // A bare IP without a port (port 80 implied) is a different origin and won't match.
        const fetchOptions: RequestInit = {
            method: request.method,
            headers: request.headers,
            mode: 'cors',
            credentials: request.credentials,
            signal: abortController.signal,
            redirect: 'follow',
        };

        // For non-GET/HEAD requests, include the body
        if (request.method !== 'GET' && request.method !== 'HEAD') {
            fetchOptions.body = await requestClone.arrayBuffer();
        }

        console.log('[SYNC-DEBUG][proxy] networkFirstApi: trying network for', {
            method: fetchOptions.method,
            url: request.url,
            mode: fetchOptions.mode,
            credentials: fetchOptions.credentials,
        });

        const response = await fetchImpl(request.url, fetchOptions);
        console.log('[SYNC-DEBUG][proxy] networkFirstApi: network SUCCESS', response.status, 'for', request.url);
        return response;
    } catch (err) {
        console.log('[SYNC-DEBUG][proxy] networkFirstApi: network FAILED, falling back to offline proxy for', request.url, err);
        return proxyFallback(request);
    } finally {
        clearTimeout(timer);
    }
}
